import { useState, useEffect, useRef } from "react";
import { motion } from "framer-motion";
import { Swiper, SwiperSlide } from "swiper/react";
import { Navigation, Pagination, Autoplay } from "swiper/modules";
import "swiper/css";
import "swiper/css/navigation";
import "swiper/css/pagination";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import cx from "@/modules/portfolio/styles/Project.module.scss";
import accessimg from "@/assets/images/access.png";
import realphbuilderimg from "@/assets/images/realphbuilder.png";
import realphimg from "@/assets/images/realph.png";
import meappimg from "@/assets/images/meapp.png";
import qtimeimg from "@/assets/images/qtime.png";
import axieimg from "@/assets/images/axie.png";
import qspaceimg from "@/assets/images/qspace.png";

gsap.registerPlugin(ScrollTrigger);

const Projects = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const sectionRef = useRef(null);

  const projects = [
    {
      title: "Access Website Builder",
      // desc: "A comprehensive website builder platform designed specifically for real estate professionals. Features drag-and-drop functionality, custom templates, and integrated CRM tools to help agents create stunning, conversion-optimized websites.",
      img: accessimg,
      link: "https://access.com/",
      technologies: [
        "React",
        "Next.js",
        "Prisma",
        "PostgreSQL",
        "Tailwind CSS",
      ],
    },
    {
      title: "Real.ph",
      // desc: "A comprehensive real estate platform revolutionizing property discovery in the Philippines. Features advanced search filters, virtual property tours, and verified listings with integrated mortgage calculators and agent matching.",
      img: realphimg,
      link: "https://real.ph/",
      technologies: ["Laravel", "MySQL", "Redis", "AWS", "Vue.js"],
    },
    {
      title: "Real Web Builder",
      // desc: "A comprehensive website builder platform designed specifically for real estate professionals. Features drag-and-drop functionality, custom templates, and integrated CRM tools to help agents create stunning, conversion-optimized websites.",
      img: realphbuilderimg,
      link: "https://builder.real.ph/",
      technologies: [
        "React",
        "Next.js",
        "Prisma",
        "PostgreSQL",
        "Tailwind CSS",
      ],
    },
    {
      title: "Me App Instant ID Maker",
      // desc: "A streamlined digital ID creation tool that generates professional identification cards instantly. Features customizable templates, high-resolution output, and batch processing capabilities for organizations.",
      img: meappimg,
      link: "https://me.forge99.com/",
      technologies: ["Laravel", "Vue.js", "Vuex", "MySQL"],
    },
    {
      title: "Axie Metaplay",
      // desc: "A comprehensive website builder platform designed specifically for real estate professionals. Features drag-and-drop functionality, custom templates, and integrated CRM tools to help agents create stunning, conversion-optimized websites.",
      img: axieimg,
      link: "https://axie.metaplayleague.com/",
      technologies: ["Vue3", "Nuxt.js", "Prisma", "PostgreSQL", "Tailwind CSS"],
    },
    {
      title: "Qtime",
      // desc: "An advanced time-tracking solution built for remote teams and freelancers. Features project-based tracking, detailed reporting, team collaboration tools, and integration with popular project management platforms.",
      img: qtimeimg,
      link: "https://qtimesoftware.com/",
      technologies: ["Laravel", "Vue.js", "PostgreSQL", "Redis"],
    },
    {
      title: "QSpace",
      // desc: "A comprehensive SaaS platform designed for the coworking and office real estate industry. Features space management, booking systems, member management, and analytics dashboard for workspace operators.",
      img: qspaceimg,
      link: "https://qtimesoftware.com/",
      technologies: ["Node.js", "Vue.js", "Express.js", "PostgreSQL"],
    },
  ];

  useEffect(() => {
    if (!sectionRef.current) return;

    const ctx = gsap.context(() => {
      const cards = gsap.utils.toArray(".project-card");
      cards.forEach((card, index) => {
        gsap.fromTo(
          card,
          { opacity: 0, y: 30, scale: 0.98 },
          {
            opacity: 1,
            y: 0,
            scale: 1,
            duration: 0.6,
            ease: "power2.out",
            delay: (index % 3) * 0.08,
            scrollTrigger: {
              trigger: card,
              start: "top 85%",
              toggleActions: "play none none reverse",
            },
          }
        );
      });
    }, sectionRef);

    return () => ctx.revert();
  }, []);

  return (
    <section ref={sectionRef} className="mb-20">
      <motion.div
        initial={{ opacity: 0, y: 50 }}
        whileInView={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8, ease: "easeOut" }}
        viewport={{ once: true }}
        className="text-center mb-8"
      >
        <h2 className="text-4xl font-bold text-gray-800 dark:text-gray-100 mb-4">
          Featured Projects
        </h2>
        <div className="w-24 h-1 bg-gradient-to-r from-blue-500 to-purple-600 mx-auto rounded-full"></div>
      </motion.div>

      <Swiper
        modules={[Navigation, Pagination, Autoplay]}
        spaceBetween={30}
        slidesPerView={1}
        navigation
        pagination={{ clickable: true }}
        autoplay={{
          delay: 5000,
          disableOnInteraction: false,
        }}
        loop={true}
        breakpoints={{
          744: {
            slidesPerView: 2,
          },
          1200: {
            slidesPerView: 3,
          },
        }}
        onSlideChange={(swiper) => setCurrentSlide(swiper.activeIndex)}
        className={cx["swiper-projects"]}
      >
        {projects.map((project, i) => (
          <SwiperSlide key={i}>
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.4, delay: i * 0.1 }}
              viewport={{ once: true }}
              className="h-full"
            >
              <div className="project-card bg-white rounded-2xl shadow-md hover:shadow-xl transition-all duration-300 transform hover:scale-105 hover:-translate-y-2 dark:bg-gray-800 dark:text-white dark:hover:bg-gray-700 p-6 h-full min-h-[32rem] flex flex-col group">
                {/* Project Image */}
                <div className="relative overflow-hidden rounded-lg mb-4">
                  <img
                    src={project.img}
                    alt={project.title}
                    className="w-full h-64 object-cover object-top transition-transform duration-300 group-hover:scale-110"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                </div>

                {/* Project Info */}
                <div className="flex-grow">
                  <h3 className="text-xl font-bold mb-3 text-gray-800 dark:text-white group-hover:text-blue-600 dark:group-hover:text-blue-400 transition-colors">
                    {project.title}
                  </h3>

                  {/* <p className="text-gray-600 dark:text-gray-300 text-sm mb-4 leading-relaxed">
                    {project.desc}
                  </p> */}

                  {/* Technologies */}
                  <div className="mb-4">
                    <h4 className="font-semibold mb-2 text-gray-700 dark:text-gray-300 text-sm">
                      Technologies Used:
                    </h4>
                    <div className="flex flex-wrap gap-2">
                      {project.technologies.map((tech, techIndex) => (
                        <span
                          key={techIndex}
                          className="px-3 py-1 bg-gradient-to-r from-blue-100 to-blue-50 hover:from-blue-200 hover:to-blue-100 text-blue-800 rounded-full text-xs font-medium transition-all duration-200 hover:scale-105 dark:from-blue-900 dark:to-blue-800 dark:text-blue-200"
                        >
                          {tech}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>

                {/* Action Button */}
                <div className="mt-auto">
                  <a
                    href={project.link}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="inline-block text-sm font-medium text-blue-600 hover:text-blue-800 hover:underline dark:text-blue-400 dark:hover:text-blue-300 transition-colors"
                  >
                    View Project →
                  </a>
                </div>
              </div>
            </motion.div>
          </SwiperSlide>
        ))}
      </Swiper>

      <div className="flex justify-center mt-10">
        {projects.map((_, index) => (
          <button
            key={index}
            className={`pagination-dot ${
              currentSlide === index ? "active" : ""
            }`}
            onClick={() => setCurrentSlide(index)}
          >
            <span></span>
          </button>
        ))}
      </div>
    </section>
  );
};

export default Projects;
