import { useEffect, useRef } from "react";
import { motion } from "framer-motion";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

const WorkExperience = () => {
  const sectionRef = useRef(null);
  const experiences = [
    {
      company: "August 99 INC (OQULO Division)",
      position: "Software Engineer 2",
      period: "May 2022 – Present",
      description:
        "Implemented new features across existing web applications using modern tech stacks such as React, Next.js and Vue js 2 and 3, enhancing functionality, performance, and user experience.",
    },
    {
      company: "August 99 INC (Culture Kings – Dojo Division)",
      position: "Web Application Developer",
      period: "May 2020 – May 2022",
      description:
        "Developed and maintained a middleware web application for product and sales order management, collaborating closely with Backend Developers from the Culture Kings Australia team to ensure seamless integration and efficient data flow.",
    },
    {
      company: "August 99 INC (OQULO Division)",
      position: "Software Engineer 1",
      period: "August 2019 – May 2020",
      description:
        "Worked closely with Senior Developers, Product Managers, QA Engineers, and Designers to deliver high-quality solutions for various projects and delivering exceptional user experiences.",
    },
    {
      company: "August 99 INC",
      position: "Web Developer Intern",
      period: "December 2018 – July 2019",
      description:
        "Gained hands-on experience in web development with modern stacks, converting design mockups from Photoshop/XD into responsive, high-quality web page prototypes that met client specifications.",
    },
  ];

  useEffect(() => {
    if (!sectionRef.current) return;

    const ctx = gsap.context(() => {
      const cards = gsap.utils.toArray(".experience-card");
      cards.forEach((card, index) => {
        gsap.fromTo(
          card,
          { opacity: 0, y: 20 },
          {
            opacity: 1,
            y: 0,
            duration: 0.6,
            ease: "power2.out",
            delay: (index % 3) * 0.08,
            scrollTrigger: {
              trigger: card,
              start: "top 90%",
              toggleActions: "play none none reverse",
            },
          }
        );
      });
    }, sectionRef);

    return () => ctx.revert();
  }, []);

  return (
    <section ref={sectionRef} className="mb-16">
      <motion.div
        initial={{ opacity: 0, y: 50 }}
        whileInView={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8, ease: "easeOut" }}
        viewport={{ once: true }}
        className="text-center mb-12"
      >
        <h2 className="text-4xl font-bold text-gray-800 dark:text-gray-100 mb-4">
          Work Experience
        </h2>
        <div className="w-24 h-1 bg-gradient-to-r from-blue-500 to-purple-600 mx-auto rounded-full"></div>
      </motion.div>
      <div className="max-w-4xl mx-auto space-y-8">
        {experiences.map((exp, i) => (
          <motion.div
            key={i}
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4, delay: i * 0.1 }}
            viewport={{ once: true }}
          >
            <div className="experience-card bg-white dark:bg-gray-800 dark:hover:bg-gray-600 hover:scale-105 rounded-xl p-6 shadow-md hover:shadow-lg transition-all">
              <div className="flex flex-col md:flex-row md:items-center md:justify-between mb-4">
                <div>
                  <h3 className="text-xl font-bold text-gray-800 dark:text-gray-100">
                    {exp.position}
                  </h3>
                  <p className="text-gray-600 dark:text-gray-300">
                    {exp.company}
                  </p>
                </div>
                <span className="text-sm text-gray-500 dark:text-gray-400 mt-2 md:mt-0">
                  {exp.period}
                </span>
              </div>
              <p className="text-gray-600 dark:text-gray-300">
                {exp.description}
              </p>
            </div>
          </motion.div>
        ))}
      </div>
    </section>
  );
};

export default WorkExperience;
